import { getConfig, hasCredentials } from "../config.js";
import { positionalArgs, UUID_RE } from "../parseArgs.js";
import { handleStudioError, openStudioTo } from "./openStudioTo.js";
export function parseTestRunIds(args) {
    const joined = args.join(",");
    const seen = new Set();
    for (const part of joined.split(",")) {
        const id = part.trim();
        if (id.length > 0 && UUID_RE.test(id)) {
            seen.add(id.toLowerCase());
        }
    }
    return Array.from(seen);
}
export function buildExperimentsPath(testRunIds) {
    const params = new URLSearchParams();
    params.set("testRunIds", testRunIds.join(","));
    return `/studio/experiments?${params.toString()}`;
}
export function buildExperimentsPathForGroup(experimentGroupId) {
    const params = new URLSearchParams();
    params.set("experimentGroupId", experimentGroupId);
    return `/studio/experiments?${params.toString()}`;
}
const ARGS = [{ name: "testRunId", variadic: true }];
export async function runOpenExperiments(_platform) {
    const args = positionalArgs(ARGS);
    const testRunIds = parseTestRunIds(args);
    if (testRunIds.length === 0) {
        console.error("Usage: openExperiments <testRunId>[,<testRunId>...] [<testRunId>...]");
        console.error("At least one valid UUID test-run id is required.");
        process.exit(1);
    }
    const config = getConfig();
    const apiKey = hasCredentials() ? config.apiKey : null;
    const targetPath = buildExperimentsPath(testRunIds);
    try {
        await openStudioTo(targetPath, { apiKey, serviceUrl: config.serviceUrl });
    }
    catch (err) {
        handleStudioError(err);
    }
    console.log("Experiments viewer opened in Studio");
    process.exit(0);
}
